- Confirms that record_ts is populated in every row of every table. -- total_rows and rows_with_ts should be equal for all tables.

SELECT 'publishers' AS table_name, COUNT() AS total_rows, COUNT(record_ts) AS rows_with_ts FROM bookstore.publishers UNION ALL SELECT 'authors', COUNT(), COUNT(record_ts) FROM bookstore.authors UNION ALL SELECT 'genres', COUNT(), COUNT(record_ts) FROM bookstore.genres UNION ALL SELECT 'books', COUNT(), COUNT(record_ts) FROM bookstore.books UNION ALL SELECT 'book_authors', COUNT(), COUNT(record_ts) FROM bookstore.book_authors UNION ALL SELECT 'book_genres', COUNT(), COUNT(record_ts) FROM bookstore.book_genres UNION ALL SELECT 'customers', COUNT(), COUNT(record_ts) FROM bookstore.customers UNION ALL SELECT 'orders', COUNT(), COUNT(record_ts) FROM bookstore.orders UNION ALL SELECT 'order_items', COUNT(), COUNT(record_ts) FROM bookstore.order_items UNION ALL SELECT 'reviews', COUNT(), COUNT(record_ts) FROM bookstore.reviews ORDER BY table_name;
